func (c *ClusterClient) PoolStats() *PoolStats {
	acc := PoolStats{}
	c.clientsMx.RLock()
	for _, client := range c.clients {
		m := client.PoolStats()
		acc.Requests += m.Requests
		acc.Waits += m.Waits
		acc.Timeouts += m.Timeouts
