func (a *Autopilot) run() {
	defer a.waitGroup.Done()

	// Monitor server health until shutdown
	ticker := time.NewTicker(a.interval)
	defer ticker.Stop()

	for {
		select {
		case <-a.shutdownCh:
			return
		case <-ticker.C:
			autopilotConfig := a.delegate.AutopilotConfig()
			if autopilotConfig == nil {
				continue
			}

			// Skip the non-voter promotions unless all servers support the new APIs
			minRaftProtocol, err := a.MinRaftProtocol()
			if err != nil {
				a.logger.Printf("[ERR] autopilot: error getting server raft protocol versions: %s", err)
				continue
			}
			if minRaftProtocol >= 3 {
				promotions, err := a.delegate.PromoteNonVoters(autopilotConfig, a.GetClusterHealth())
				if err != nil {
					a.logger.Printf("[ERR] autopilot: Error checking for non-voters to promote: %s", err)
				}
				if err := a.handlePromotions(promotions); err != nil {
					a.logger.Printf("[ERR] autopilot: Error handling promotions: %s", err)
				}
			}

			if err := a.pruneDeadServers(); err != nil {
				a.logger.Printf("[ERR] autopilot: Error checking for dead servers to remove: %s", err)
			}
		case <-a.removeDeadCh:
			autopilotConfig := a.delegate.AutopilotConfig()
			if autopilotConfig == nil {
				continue
			}

			if err := a.pruneDeadServers(); err != nil {
				a.logger.Printf("[ERR] autopilot: Error checking for dead servers to remove: %s", err)
			}
		}
	}
}

func (s *Server) listenersFromSnapshotConnectProxy(cfgSnap *proxycfg.ConfigSnapshot, token string) ([]proto.Message, error) {
	// One listener for each upstream plus the public one
	resources := make([]proto.Message, len(cfgSnap.Proxy.Upstreams)+1)

	// Configure public listener
	var err error
	resources[0], err = s.makePublicListener(cfgSnap, token)
	if err != nil {
		return nil, err
	}
	for i, u := range cfgSnap.Proxy.Upstreams {
		resources[i+1], err = s.makeUpstreamListener(&u)
		if err != nil {
			return nil, err
		}
	}
	return resources, nil
}

func (l *raftLog) compact(i int64) int64 {
	if l.isOutOfBounds(i) {
		panic(fmt.Sprintf("compact %d out of bounds [%d:%d]", i, l.offset, l.lastIndex()))
	}
	l.ents = l.slice(i, l.lastIndex()+1)
	l.unstable = max(i+1, l.unstable)
	l.offset = i
	return int64(len(l.ents))
}

