func (wg *watcherGroup) add(rid receiverID, w watcher) int64 {
	wg.mu.Lock()
	defer wg.mu.Unlock()
	if wg.rev > w.rev {
		return -1
	}
	wg.receivers[rid] = w
	return wg.rev
}

