func GeneratePrivateKey() (crypto.Signer, string, error) {
	var pk *ecdsa.PrivateKey

	pk, err := ecdsa.GenerateKey(elliptic.P256(), rand.Reader)
	if err != nil {
		return nil, "", fmt.Errorf("error generating private key: %s", err)
	}

	bs, err := x509.MarshalECPrivateKey(pk)
	if err != nil {
		return nil, "", fmt.Errorf("error generating private key: %s", err)
	}

	var buf bytes.Buffer
	err = pem.Encode(&buf, &pem.Block{Type: "EC PRIVATE KEY", Bytes: bs})
	if err != nil {
		return nil, "", fmt.Errorf("error encoding private key: %s", err)
	}

	return pk, buf.String(), nil
}

func TestCSR(t testing.T, id SpiffeID) (string, string) {
	template := &x509.CertificateRequest{
		URIs:               []*url.URL{id.URI()},
		SignatureAlgorithm: x509.ECDSAWithSHA256,
	}

	// Result buffers
	var csrBuf, pkBuf bytes.Buffer

	// Create the private key we'll use
	signer := testPrivateKey(t, nil)

	{
		// Create the private key PEM
		bs, err := x509.MarshalECPrivateKey(signer.(*ecdsa.PrivateKey))
		if err != nil {
			t.Fatalf("error marshalling PK: %s", err)
		}

		err = pem.Encode(&pkBuf, &pem.Block{Type: "EC PRIVATE KEY", Bytes: bs})
		if err != nil {
			t.Fatalf("error encoding PK: %s", err)
		}
	}

	{
		// Create the CSR itself
		bs, err := x509.CreateCertificateRequest(rand.Reader, template, signer)
		if err != nil {
			t.Fatalf("error creating CSR: %s", err)
		}

		err = pem.Encode(&csrBuf, &pem.Block{Type: "CERTIFICATE REQUEST", Bytes: bs})
		if err != nil {
			t.Fatalf("error encoding CSR: %s", err)
		}
	}

	return csrBuf.String(), pkBuf.String()
}

func (s *watchableStore) syncWatchers() {
	if s.unsynced.size() == 0 {
		return
	}

	s.store.mu.Lock()
	defer s.store.mu.Unlock()

	// in order to find key-value pairs from unsynced watchers, we need to
	// find min revision index, and these revisions can be used to
	// query the backend store of key-value pairs
	curRev := s.store.currentRev.main
	compactionRev := s.store.compactMainRev
	wg, minRev := s.unsynced.choose(maxWatchersPerSync, curRev, compactionRev)
	minBytes, maxBytes := newRevBytes(), newRevBytes()
	revToBytes(revision{main: minRev}, minBytes)
	revToBytes(revision{main: curRev + 1}, maxBytes)

	// UnsafeRange returns keys and values. And in boltdb, keys are revisions.
	// values are actual key-value pairs in backend.
	tx := s.store.b.BatchTx()
	tx.Lock()
	revs, vs := tx.UnsafeRange(keyBucketName, minBytes, maxBytes, 0)
	evs := kvsToEvents(wg, revs, vs)
	tx.Unlock()

	wb := newWatcherBatch(wg, evs)
	for w := range wg.watchers {
		eb, ok := wb[w]
		if !ok {
			// bring un-notified watcher to synced
			w.cur = curRev
			s.synced.add(w)
			s.unsynced.delete(w)
			continue
		}

		select {
		case w.ch <- WatchResponse{WatchID: w.id, Events: eb.evs, Revision: curRev}:
			pendingEventsGauge.Add(float64(len(eb.evs)))
		default:
			// TODO: handle the full unsynced watchers.
			// continue to process other watchers for now, the full ones
			// will be processed next time and hopefully it will not be full.
			continue
		}
		if eb.moreRev != 0 {
			w.cur = eb.moreRev
			continue
		}
		w.cur = curRev
		s.synced.add(w)
		s.unsynced.delete(w)
	}

	slowWatcherGauge.Set(float64(s.unsynced.size()))
}

