	s.Start()
	s.RemoveNode(context.TODO(), 1)
	action := n.Action()
	s.Stop()

	waction := []string{"ProposeConfigChange:ConfigChangeRemoveNode", "ApplyConfigChange:ConfigChangeRemoveNode"}
	if !reflect.DeepEqual(action, waction) {
		t.Errorf("action = %v, want %v", action, waction)
	}
}

