func (s *PeerServer) setMode(mode Mode) {
	s.mode = mode

	switch mode {
	case PeerMode:
		if !s.raftServer.Running() {
			s.raftServer.Start()
		}
	case StandbyMode:
		if s.raftServer.Running() {
			s.raftServer.Stop()
		}
	}
}

